function loadProfile(userId) {
  return fetchService.get(`/user/${userId}`)
    .then(res => res.data)
    .catch(err => console.error(err));
}

examples.toCode:
Future<Map<String, dynamic>> loadProfile(String userId) async {
  try {
    final res = await fetchService.get('/user/$userId');
    return res.data;
  } catch (err) {
    print(err);
    rethrow;
  }
}
